    ccfg = (cfg or {}).get("claude_code") if isinstance(cfg, dict) else {}
    if isinstance(ccfg, dict) and ccfg.get("web_chat_session_bridge") is False:
        return False
    return channel_delivery_mode(cfg) == "llm"


